@* Reusable message/reply input *@

<div class="chat-message-input">
    <textarea class="form-control" rows="2"
              placeholder="@Placeholder"
              @bind="text"
              @onkeydown="HandleKeyDown" />
    <button class="btn btn-primary btn-sm mt-1" @onclick="HandleSend" disabled="@string.IsNullOrWhiteSpace(text)">
        @ButtonLabel
    </button>
</div>

@code {
    private string text = string.Empty;

    [Parameter] public string Placeholder { get; set; } = "Type a message…";
    [Parameter] public string ButtonLabel { get; set; } = "Send";
    [Parameter] public EventCallback<string> OnSend { get; set; }

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e is { Key: "Enter", ShiftKey: false })
        {
            await HandleSend();
        }
    }

    private async Task HandleSend()
    {
        if (string.IsNullOrWhiteSpace(text)) return;
        var content = text.Trim();
        text = string.Empty;
        await OnSend.InvokeAsync(content);
    }
}

.chat-message-input {
    display: flex;
    flex-direction: column;
    padding: 0.5rem;
    border-top: 1px solid var(--bs-border-color, #dee2e6);
    background: var(--bs-body-bg, #fff);
}

.chat-message-input textarea {
    resize: none;
    font-size: 0.9rem;
}

.chat-message-input .btn {
    align-self: flex-end;
}

@using sv_3cf850765fff457492468bcf45a8d819.Models

<div class="channel-item @(IsActive ? "active" : "")" @onclick="HandleClick">
    <div class="channel-header">
        <span class="channel-name"># @Channel.Name</span>
        @if (Channel.UnreadCount > 0)
        {
            <span class="badge bg-danger rounded-pill">@Channel.UnreadCount</span>
        }
    </div>
    @if (!string.IsNullOrWhiteSpace(Channel.Description))
    {
        <div class="channel-desc text-muted">@TruncatedDescription</div>
    }
</div>

@code {
    [Parameter, EditorRequired] public Channel Channel { get; set; } = default!;
    [Parameter] public bool IsActive { get; set; }
    [Parameter] public EventCallback<int> OnSelected { get; set; }

    private string TruncatedDescription =>
        Channel.Description.Length > 40
            ? Channel.Description[..40] + "…"
            : Channel.Description;

    private async Task HandleClick() => await OnSelected.InvokeAsync(Channel.Id);
}

