@using sv_3cf850765fff457492468bcf45a8d819.Models
@inject IJSRuntime JS
@implements IAsyncDisposable

<div class="message-list-container">
    @if (IsLoadingOlder)
    {
        <div class="text-center py-2">
            <div class="spinner-border spinner-border-sm text-secondary" role="status">
                <span class="visually-hidden">Loading…</span>
            </div>
        </div>
    }
    <div class="message-list" id="@scrollContainerId">
        @foreach (var msg in Messages)
        {
            <MessageItem Message="msg"
                         ReplyCount="GetReplyCount(msg.Id)"
                         OnOpenThread="OnOpenThread"
                         OnReact="OnReact" />
        }
    </div>
</div>

@code {
    private string scrollContainerId = $"msg-list-{Guid.NewGuid():N}";
    private IJSObjectReference? module;

    [Parameter] public List<Message> Messages { get; set; } = [];
    [Parameter] public Dictionary<int, ThreadSummary> ThreadSummaries { get; set; } = [];
    [Parameter] public bool IsLoadingOlder { get; set; }
    [Parameter] public EventCallback OnScrolledToTop { get; set; }
    [Parameter] public EventCallback<int> OnOpenThread { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }

    private int GetReplyCount(int messageId) =>
        ThreadSummaries.TryGetValue(messageId, out var s) ? s.ReplyCount : 0;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            module = await JS.InvokeAsync<IJSObjectReference>("import", "./js/chatScroll.js");
            var dotNetRef = DotNetObjectReference.Create(this);
            await module.InvokeVoidAsync("initialize", dotNetRef, scrollContainerId);
            await module.InvokeVoidAsync("scrollToBottom", scrollContainerId);
        }
    }

    [JSInvokable]
    public async Task OnScrolledToTop()
    {
        await OnScrolledToTop.InvokeAsync();
    }

    public async Task ScrollToBottomAsync()
    {
        if (module is not null)
        {
            await module.InvokeVoidAsync("scrollToBottom", scrollContainerId);
        }
    }

    public async Task<double> GetScrollHeightAsync()
    {
        if (module is not null)
            return await module.InvokeAsync<double>("getScrollHeight", scrollContainerId);
        return 0;
    }

    public async Task PreserveScrollAsync(double previousScrollHeight)
    {
        if (module is not null)
            await module.InvokeVoidAsync("preserveScrollPosition", scrollContainerId, previousScrollHeight);
    }

    public async ValueTask DisposeAsync()
    {
        if (module is not null)
        {
            await module.InvokeVoidAsync("dispose", scrollContainerId);
            await module.DisposeAsync();
        }
    }
}

