@using sv_3cf850765fff457492468bcf45a8d819.Models

<div class="thread-panel">
    <div class="thread-header">
        <h6 class="mb-0 fw-bold">Thread</h6>
        <button class="btn btn-sm btn-outline-secondary" @onclick="OnClose" title="Close thread">✕</button>
    </div>

    @if (RootMessage is not null)
    {
        <div class="thread-root-message">
            <div class="fw-bold small">@RootMessage.Author</div>
            <div class="small">@RootMessage.Content</div>
        </div>
    }

    <div class="thread-replies">
        @if (Replies is not null)
        {
            @foreach (var reply in Replies)
            {
                <MessageItem Message="reply"
                             ReplyCount="0"
                             OnOpenThread="NoOp"
                             OnReact="OnReact" />
            }
        }
    </div>

    <MessageInput Placeholder="Reply in thread…"
                  ButtonLabel="Reply"
                  OnSend="OnSendReply" />
</div>

@code {
    [Parameter] public Message? RootMessage { get; set; }
    [Parameter] public List<Message>? Replies { get; set; }
    [Parameter] public EventCallback OnClose { get; set; }
    [Parameter] public EventCallback<string> OnSendReply { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }

    private static EventCallback<int> NoOp => EventCallback<int>.Empty;
}

