.message-item {
    position: relative;
    padding: 0.5rem 0.75rem;
    border-radius: 0.375rem;
    transition: background-color 0.15s;
}

.message-item:hover {
    background-color: rgba(0, 0, 0, 0.03);
}

.message-header {
    display: flex;
    align-items: baseline;
    gap: 0.5rem;
}

.message-author {
    font-size: 0.9rem;
}

.message-time {
    font-size: 0.75rem;
}

.message-content {
    font-size: 0.9rem;
    margin-top: 0.15rem;
    white-space: pre-wrap;
    word-break: break-word;
}

.reaction-bar {
    display: flex;
    flex-wrap: wrap;
    gap: 0.25rem;
    margin-top: 0.35rem;
}

.reaction-badge {
    font-size: 0.78rem;
    padding: 0.1rem 0.4rem;
    border-radius: 1rem;
    display: inline-flex;
    align-items: center;
    gap: 0.2rem;
}

.thread-link {
    font-size: 0.8rem;
    margin-top: 0.25rem;
    text-decoration: none;
}

.message-actions {
    position: absolute;
    top: -0.5rem;
    right: 0.5rem;
    display: flex;
    gap: 0.25rem;
    background: var(--bs-body-bg, #fff);
    border: 1px solid var(--bs-border-color, #dee2e6);
    border-radius: 0.375rem;
    padding: 0.15rem;
    box-shadow: 0 1px 4px rgba(0, 0, 0, 0.1);
    z-index: 10;
}

.emoji-picker-wrapper {
    position: relative;
}

.emoji-picker {
    position: absolute;
    top: 100%;
    right: 0;
    display: flex;
    gap: 0.15rem;
    background: var(--bs-body-bg, #fff);
    border: 1px solid var(--bs-border-color, #dee2e6);
    border-radius: 0.375rem;
    padding: 0.3rem;
    box-shadow: 0 2px 8px rgba(0, 0, 0, 0.15);
    z-index: 20;
    white-space: nowrap;
}

.emoji-option {
    font-size: 1.2rem;
    padding: 0.1rem 0.3rem;
    line-height: 1;
}

.emoji-option:hover {
    background-color: rgba(0, 0, 0, 0.08);
    border-radius: 0.25rem;
}

