@page "/chat"
@using sv_3cf850765fff457492468bcf45a8d819.Components.Chat
@using sv_3cf850765fff457492468bcf45a8d819.Models
@inject IChatService ChatService
@rendermode InteractiveServer

<PageTitle>Chat</PageTitle>

<div class="chat-layout">
    <div class="chat-sidebar">
        <ChannelSidebar Channels="channels"
                        ActiveChannelId="activeChannelId"
                        OnChannelSelected="SelectChannel" />
    </div>

    <div class="chat-main @(threadRootMessage is null ? "chat-main-full" : "")">
        @if (activeChannel is not null)
        {
            <div class="chat-main-header">
                <h5 class="mb-0"># @activeChannel.Name</h5>
                <span class="text-muted small">@activeChannel.Description</span>
            </div>

            <MessageList @ref="messageListRef"
                         Messages="messages"
                         ThreadSummaries="threadSummaries"
                         IsLoadingOlder="isLoadingOlder"
                         OnScrolledToTop="LoadOlderMessages"
                         OnOpenThread="OpenThread"
                         OnReact="HandleReaction" />

            <MessageInput Placeholder="Message #@activeChannel.Name"
                          OnSend="SendMessage" />
        }
        else
        {
            <div class="d-flex align-items-center justify-content-center h-100 text-muted">
                <span>Select a channel to start chatting</span>
            </div>
        }
    </div>

    @if (threadRootMessage is not null)
    {
        <div class="chat-thread">
            <ThreadPanel RootMessage="threadRootMessage"
                         Replies="threadReplies"
                         OnClose="CloseThread"
                         OnSendReply="SendThreadReply"
                         OnReact="HandleReaction" />
        </div>
    }
</div>

@code {
    private const int PageSize = 30;

    private List<Channel> channels = [];
    private List<Message> messages = [];
    private Dictionary<int, ThreadSummary> threadSummaries = [];
    private List<Message>? threadReplies;
    private Message? threadRootMessage;
    private Channel? activeChannel;
    private int activeChannelId;
    private bool isLoadingOlder;
    private bool hasMoreMessages = true;
    private MessageList? messageListRef;

    protected override async Task OnInitializedAsync()
    {
        channels = await ChatService.GetChannelsAsync();
        if (channels.Count > 0)
        {
            await SelectChannel(channels[0].Id);
        }
    }

    private async Task SelectChannel(int channelId)
    {
        activeChannelId = channelId;
        activeChannel = channels.FirstOrDefault(c => c.Id == channelId);
        messages = [];
        threadSummaries = [];
        hasMoreMessages = true;

        CloseThreadInternal();

        var loaded = await ChatService.GetMessagesAsync(channelId, 0, PageSize);
        messages = loaded;
        hasMoreMessages = loaded.Count >= PageSize;

        BuildThreadSummaries();
        await ChatService.MarkChannelReadAsync(channelId);
        StateHasChanged();

        if (messageListRef is not null)
        {
            await Task.Yield();
            await messageListRef.ScrollToBottomAsync();
        }
    }

    private async Task LoadOlderMessages()
    {
        if (isLoadingOlder || !hasMoreMessages || activeChannel is null) return;

        isLoadingOlder = true;
        StateHasChanged();

        double prevHeight = 0;
        if (messageListRef is not null)
            prevHeight = await messageListRef.GetScrollHeightAsync();

        var older = await ChatService.GetMessagesAsync(activeChannel.Id, messages.Count, PageSize);
        if (older.Count < PageSize)
            hasMoreMessages = false;

        messages.InsertRange(0, older);
        BuildThreadSummaries();
        isLoadingOlder = false;
        StateHasChanged();

        if (messageListRef is not null && prevHeight > 0)
        {
            await Task.Yield();
            await messageListRef.PreserveScrollAsync(prevHeight);
        }
    }

    private async Task SendMessage(string content)
    {
        if (activeChannel is null) return;

        var msg = await ChatService.SendMessageAsync(activeChannel.Id, content, null);
        messages.Add(msg);
        StateHasChanged();

        if (messageListRef is not null)
        {
            await Task.Yield();
            await messageListRef.ScrollToBottomAsync();
        }
    }

    private async Task OpenThread(int rootMessageId)
    {
        threadRootMessage = messages.FirstOrDefault(m => m.Id == rootMessageId);
        if (threadRootMessage is null) return;

        threadReplies = await ChatService.GetThreadAsync(rootMessageId);
        StateHasChanged();
    }

    private void CloseThread()
    {
        CloseThreadInternal();
        StateHasChanged();
    }

    private void CloseThreadInternal()
    {
        threadRootMessage = null;
        threadReplies = null;
    }

    private async Task SendThreadReply(string content)
    {
        if (activeChannel is null || threadRootMessage is null) return;

        var reply = await ChatService.SendMessageAsync(activeChannel.Id, content, threadRootMessage.Id);
        threadReplies ??= [];
        threadReplies.Add(reply);

        // Update thread summary
        threadSummaries[threadRootMessage.Id] = new ThreadSummary(
            threadRootMessage.Id,
            threadReplies.Count,
            reply.SentAt);

        StateHasChanged();
    }

    private async Task HandleReaction((int MessageId, string Emoji) args)
    {
        await ChatService.AddReactionAsync(args.MessageId, args.Emoji);

        // Optimistically update the message in whichever list it belongs to
        UpdateReactionInList(messages, args.MessageId, args.Emoji);
        if (threadReplies is not null)
            UpdateReactionInList(threadReplies, args.MessageId, args.Emoji);

        StateHasChanged();
    }

    private static void UpdateReactionInList(List<Message> list, int messageId, string emoji)
    {
        var idx = list.FindIndex(m => m.Id == messageId);
        if (idx < 0) return;

        var msg = list[idx];
        var existing = msg.Reactions.FirstOrDefault(r => r.Emoji == emoji);
        if (existing is not null)
        {
            if (!existing.Users.Contains("You"))
                existing.Users.Add("You");
        }
        else
        {
            msg.Reactions.Add(new Reaction(emoji, ["You"]));
        }
    }

    private void BuildThreadSummaries()
    {
        threadSummaries.Clear();
        // Build summaries from messages that are replies (have ReplyToId)
        var replies = messages.Where(m => m.ReplyToId is not null).ToList();
        foreach (var group in replies.GroupBy(m => m.ReplyToId!.Value))
        {
            threadSummaries[group.Key] = new ThreadSummary(
                group.Key,
                group.Count(),
                group.Max(m => m.SentAt));
        }
    }
}

